/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    VendTrans vendTrans;
    VendTable vendTable;
    LogisticsLocation logisticsLocation;

    ttsbegin;
    while select forUpdate vendTrans where vendTrans.DataAreaId == "E016"
    {
        select firstOnly vendTable
    where vendTable.AccountNum == vendTrans.AccountNum;

        if (vendTable)
        {
            select firstOnly logisticsLocation
        where logisticsLocation.Description == vendTable.name();

            if (logisticsLocation)
            {
                vendTrans.RemittanceLocation = logisticsLocation.RecId;
                vendTrans.update();
            }

        }

    }
    ttscommit;

}
